class Solution {
    public long minimumSteps(String s) {
        long steps = 0;
        int countOnes = 0;
        for (char c : s.toCharArray()) {
            if (c == '0') {
                steps += countOnes;
            } else {
                countOnes++;
            }
        }
        return steps;
    }
}

